/**
 * @brief Flush dirty region if any, then clear dirty state on success.
 * @return true if no dirty data existed or flush succeeded
 */
bool gfx_flush_dirty(gfx_framebuffer_t *framebuffer);

#ifdef __cplusplus
}
#endif

#endif /* ILI9488_GFX_H */
